return [
  { json: { module: 'JobOpenings' } },
  { json: { module: 'Applications' } },
  { json: { module: 'Interviews' } },
  { json: { module: 'Candidates' } },
  { json: { module: 'Clients' } },
  { json: { module: 'Hiring_Managers' } }
];

const items = $input.all();
let markdown = "# Zoho Recruit API Reference (Auto-Generated on " + new Date().toISOString().split('T')[0] + ")\n\n";
markdown += "This document provides the latest API field names and schemas retrieved directly from Zoho Recruit.\n\n";

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const moduleName = $('Set Modules').itemMatching(i).json.module;

  markdown += "## " + (i + 1) + ". " + moduleName + " Module\n\n";

  // Check if Zoho - Get Fields succeeded
  const fieldsNode = $('Zoho - Get Fields').itemMatching(i);
  const hasOfficialFields = fieldsNode && fieldsNode.json && Array.isArray(fieldsNode.json.fields);

  if (hasOfficialFields) {
    markdown += "| API Field Name | Display Label | Data Type | Mandatory | Custom |\n";
    markdown += "|---|---|---|---|---|\n";
    for (const field of fieldsNode.json.fields) {
      const apiName = field.api_name || '';
      const label = field.field_label || '';
      const type = field.json_type || '';
      const mandatory = field.system_mandatory ? '✅ Yes' : 'No';
      const custom = field.custom_field ? '✅ Yes' : 'No';
      markdown += "| `" + apiName + "` | " + label + " | " + type + " | " + mandatory + " | " + custom + " |\n";
    }
  } else {
    // Use fallback record keys
    const fallbackNode = $('Zoho - Get Fallback Record').itemMatching(i);
    const hasRecord = fallbackNode && fallbackNode.json && Array.isArray(fallbackNode.json.data) && fallbackNode.json.data.length > 0;

    if (hasRecord) {
      markdown += "> [!NOTE]\n";
      markdown += "> This module was documented using the **Record Schema Fallback** because the settings API returned a scope mismatch.\n\n";
      markdown += "| API Field Name | Sample Value / Structure | Data Type | Source |\n";
      markdown += "|---|---|---|---|\n";

      const record = fallbackNode.json.data[0];
      const keys = Object.keys(record).sort();

      for (const key of keys) {
        const val = record[key];
        let typeStr = typeof val;
        let sampleVal = '';

        if (val === null) {
          typeStr = 'null';
          sampleVal = '*null*';
        } else if (Array.isArray(val)) {
          typeStr = 'array (lookup)';
          sampleVal = val.length > 0 ? JSON.stringify(val[0]) : '[]';
        } else if (typeof val === 'object') {
          typeStr = 'object (lookup)';
          sampleVal = JSON.stringify(val);
        } else {
          sampleVal = String(val);
        }

        if (sampleVal.length > 80) {
          sampleVal = sampleVal.substring(0, 77) + '...';
        }

        markdown += "| `" + key + "` | `" + sampleVal.replace(/\|/g, '\\|') + "` | " + typeStr + " | Fallback Key |\n";
      }
    } else {
      markdown += "❌ *Could not retrieve field data or records for this module.*\n\n";
      if (fieldsNode && fieldsNode.json && fieldsNode.json.message) {
        markdown += "Settings error: `" + fieldsNode.json.message + "`\n\n";
      }
      if (fallbackNode && fallbackNode.json && fallbackNode.json.message) {
        markdown += "Records error: `" + fallbackNode.json.message + "`\n\n";
      }
    }
  }

  markdown += "\n---\n\n";
}

markdown += "*Generated by n8n Webhook Automation.*";

return [{ json: { markdown: markdown } }];
